resource "datadog_monitor" "llm_error_rate" {
  name    = "GenAI [feature-name]: error rate"
  type    = "metric alert"
  message = "LLM error rate is {{value}}%. Check runbook: [URL] @pagerduty-oncall"

  query = "sum(last_5m):sum:llm.errors{feature:feature_name}.as_count() / sum:llm.requests{feature:feature_name}.as_count() * 100 > 2"

  thresholds = {
    critical = 2
    warning  = 1
  }

  tags = ["service:feature-name", "env:production", "team:ml-platform"]
}

resource "datadog_monitor" "llm_cost_spike" {
  name    = "GenAI [feature-name]: cost spike"
  type    = "metric alert"
  message = "Cost per hour is {{value}}× baseline. Possible runaway tokens. @pagerduty-oncall"

  query = "avg(last_10m):avg:llm.cost_usd{feature:feature_name} > ${7_day_avg * 2}"

  thresholds = {
    critical = "${7_day_avg * 2}"
    warning  = "${7_day_avg * 1.5}"
  }
}
